using System;
using System.IO;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===");
        Console.WriteLine();

        // Collect all errors and warnings
        Console.WriteLine("=== ALL ERRORS ===");
        build.VisitAllChildren<Error>(error =>
        {
            var parent = error.Parent;
            string projectName = "";
            while (parent != null)
            {
                if (parent is Project p)
                {
                    projectName = p.Name;
                    break;
                }
                parent = parent.Parent;
            }
            Console.WriteLine($"[ERROR] Project: {projectName}");
            Console.WriteLine($"  Code: {error.Code}");
            Console.WriteLine($"  File: {error.File}");
            Console.WriteLine($"  Line: {error.LineNumber}");
            Console.WriteLine($"  Message: {error.Text}");
            Console.WriteLine();
        });

        Console.WriteLine("=== ALL WARNINGS ===");
        build.VisitAllChildren<Warning>(warning =>
        {
            var parent = warning.Parent;
            string projectName = "";
            while (parent != null)
            {
                if (parent is Project p)
                {
                    projectName = p.Name;
                    break;
                }
                parent = parent.Parent;
            }
            Console.WriteLine($"[WARN] Project: {projectName}");
            Console.WriteLine($"  Code: {warning.Code}");
            Console.WriteLine($"  File: {warning.File}");
            Console.WriteLine($"  Line: {warning.LineNumber}");
            Console.WriteLine($"  Message: {warning.Text}");
            Console.WriteLine();
        });

        // Show project dependency tree
        Console.WriteLine("=== PROJECT BUILD ORDER ===");
        build.VisitAllChildren<Project>(project =>
        {
            Console.WriteLine($"Project: {project.Name} -> Succeeded: {project.Succeeded}");
        });
    }
}
