using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===\n");

        // Collect all errors
        var errors = new List<(string Project, string Code, string File, int Line, string Message, string Subcategory)>();
        build.VisitAllChildren<Error>(error =>
        {
            var parent = error.Parent;
            string projectName = "";
            while (parent != null)
            {
                if (parent is Project p)
                {
                    projectName = p.Name;
                    break;
                }
                parent = parent.Parent;
            }
            errors.Add((projectName, error.Code, error.File, error.LineNumber, error.Text, error.Subcategory ?? ""));
        });

        // Deduplicate errors
        var uniqueErrors = errors.Distinct().ToList();
        Console.WriteLine($"=== {uniqueErrors.Count} UNIQUE ERRORS ===");
        foreach (var e in uniqueErrors)
        {
            Console.WriteLine($"[{e.Code}] {e.Project} | {Path.GetFileName(e.File)}:{e.Line}");
            Console.WriteLine($"  {e.Message}");
            if (!string.IsNullOrEmpty(e.Subcategory))
                Console.WriteLine($"  Subcategory: {e.Subcategory}");
            Console.WriteLine();
        }

        // Show all messages that look like failures
        Console.WriteLine("=== FAILED TARGETS ===");
        build.VisitAllChildren<Target>(target =>
        {
            if (target.HasChildren)
            {
                bool hasError = false;
                target.VisitAllChildren<Error>(e => hasError = true);
                if (hasError)
                {
                    var parent = target.Parent;
                    string projectName = "";
                    while (parent != null)
                    {
                        if (parent is Project p)
                        {
                            projectName = p.Name;
                            break;
                        }
                        parent = parent.Parent;
                    }
                    Console.WriteLine($"  Target: {target.Name} in {projectName}");
                }
            }
        });
        Console.WriteLine();

        // Check for MSB4181 or other cascading error patterns
        Console.WriteLine("=== CHECKING FOR CASCADING FAILURES ===");
        var projectsWithErrors = uniqueErrors.Select(e => e.Project).Distinct().ToList();
        Console.WriteLine($"Projects with direct errors: {string.Join(", ", projectsWithErrors)}");

        // Check if Api project had build failures due to dependency
        build.VisitAllChildren<Message>(msg =>
        {
            if (msg.Text != null && (msg.Text.Contains("MSB3202") || msg.Text.Contains("could not be loaded") || 
                msg.Text.Contains("dependency") && msg.Text.Contains("failed") ||
                msg.Text.Contains("not build") || msg.Text.Contains("project reference")))
            {
                var parent = msg.Parent;
                string projectName = "";
                while (parent != null)
                {
                    if (parent is Project p)
                    {
                        projectName = p.Name;
                        break;
                    }
                    parent = parent.Parent;
                }
                Console.WriteLine($"  [{projectName}] {msg.Text.Substring(0, Math.Min(200, msg.Text.Length))}");
            }
        });

        // Look at all source file content available
        Console.WriteLine("\n=== SOURCE FILE ITEMS ===");
        build.VisitAllChildren<Item>(item =>
        {
            if (item.Name == "Compile" && item.Text != null && !item.Text.Contains("obj/"))
            {
                var parent = item.Parent;
                string projectName = "";
                while (parent != null)
                {
                    if (parent is Project p)
                    {
                        projectName = p.Name;
                        break;
                    }
                    parent = parent.Parent;
                }
                Console.WriteLine($"  [{projectName}] Compile: {item.Text}");
            }
        });

        // Show PackageReferences
        Console.WriteLine("\n=== PACKAGE REFERENCES ===");
        build.VisitAllChildren<Item>(item =>
        {
            if (item.Name == "PackageReference")
            {
                var parent = item.Parent;
                string projectName = "";
                while (parent != null)
                {
                    if (parent is Project p)
                    {
                        projectName = p.Name;
                        break;
                    }
                    parent = parent.Parent;
                }
                Console.WriteLine($"  [{projectName}] Package: {item.Text}");
            }
        });

        // Check for source content in SourceFile nodes
        Console.WriteLine("\n=== COMPILER COMMAND LINES ===");
        build.VisitAllChildren<Task>(task =>
        {
            if (task.Name == "Csc")
            {
                var parent = task.Parent;
                string projectName = "";
                while (parent != null)
                {
                    if (parent is Project p)
                    {
                        projectName = p.Name;
                        break;
                    }
                    parent = parent.Parent;
                }
                var cmdLine = task.CommandLineArguments;
                if (cmdLine != null)
                {
                    // Extract references from command line
                    var refs = cmdLine.Split('\n')
                        .Where(l => l.TrimStart().StartsWith("/reference:"))
                        .Select(l => Path.GetFileName(l.Trim().Replace("/reference:", "")))
                        .ToList();
                    Console.WriteLine($"  [{projectName}] References: {string.Join(", ", refs)}");
                }
            }
        });
    }
}
CSHARP

