using System;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        // Check which projects' CoreCompile target ran
        Console.WriteLine("=== CORECOMPILE TARGET INVOCATIONS ===");
        build.VisitAllChildren<Target>(target =>
        {
            if (target.Name == "CoreCompile")
            {
                var parent = target.Parent;
                string projectName = "";
                while (parent != null)
                {
                    if (parent is Project p) { projectName = p.Name; break; }
                    parent = parent.Parent;
                }
                Console.WriteLine($"  {projectName}: CoreCompile invoked");
            }
        });

        // Check for "Build FAILED" or skipped messages
        Console.WriteLine("\n=== BUILD/SKIP MESSAGES ===");
        build.VisitAllChildren<Message>(msg =>
        {
            if (msg.Text != null && (
                msg.Text.Contains("Build FAILED") || 
                msg.Text.Contains("was not built") ||
                msg.Text.Contains("Building with") ||
                msg.Text.Contains("Skipping") && msg.Text.Contains("project") ||
                msg.Text.Contains("did not build")))
            {
                var parent = msg.Parent;
                string projectName = "";
                while (parent != null)
                {
                    if (parent is Project p) { projectName = p.Name; break; }
                    parent = parent.Parent;
                }
                Console.WriteLine($"  [{projectName}] {msg.Text}");
            }
        });

        // Check for project.assets.json content - NuGet resolved packages
        Console.WriteLine("\n=== RESOLVED PACKAGE REFERENCES ===");
        build.VisitAllChildren<AddItem>(addItem =>
        {
            if (addItem.Name == "ResolvedCompileFileDefinitions" || 
                addItem.Name == "NativeCopyLocalItems" ||
                addItem.Name == "_ResolvedPackageReference" ||
                addItem.Name == "PackageReference")
            {
                var parent = addItem.Parent;
                string projectName = "";
                while (parent != null)
                {
                    if (parent is Project p) { projectName = p.Name; break; }
                    parent = parent.Parent;
                }
                foreach (var child in addItem.Children)
                {
                    if (child is Item item)
                    {
                        var text = item.Text;
                        if (text.Contains("Newtonsoft") || addItem.Name == "PackageReference")
                        {
                            Console.Write($"  [{projectName}] {addItem.Name}: {text}");
                            foreach (var meta in item.Children.OfType<Metadata>())
                                Console.Write($" {meta.Name}={meta.Value}");
                            Console.WriteLine();
                        }
                    }
                }
            }
        });

        // Check the project evaluation for item additions
        Console.WriteLine("\n=== EVALUATION ITEMS ===");
        build.VisitAllChildren<ProjectEvaluation>(eval =>
        {
            bool printed = false;
            eval.VisitAllChildren<NamedNode>(node =>
            {
                if (node.Name == "PackageReference" && node is AddItem addItem)
                {
                    if (!printed) { Console.WriteLine($"\n  Evaluation: {eval.Name}"); printed = true; }
                    foreach (var child in addItem.Children)
                    {
                        if (child is Item item)
                        {
                            Console.Write($"    PackageRef: {item.Text}");
                            foreach (var meta in item.Children.OfType<Metadata>())
                                Console.Write($" {meta.Name}={meta.Value}");
                            Console.WriteLine();
                        }
                    }
                }
            });
        });

        // Check for MSBuild "project X failed" messages
        Console.WriteLine("\n=== PROJECT OUTCOMES ===");
        build.VisitAllChildren<Project>(project =>
        {
            bool hasErrors = false;
            project.VisitAllChildren<Error>(e => hasErrors = true);

            // Check if Build target was the entrypoint and if it completed
            string targets = "";
            foreach (var child in project.Children)
            {
                if (child is Target t)
                    targets += t.Name + " ";
            }
            Console.WriteLine($"  {project.Name} (EntryTargets: {project.EntryTargets}) HasErrors={hasErrors}");
        });
    }
}
